57	```rust
58	# fn blah() -> Result<(), std::io::Error> {
59	# let lines = vec!["one", "two", "three"];
60	use std::io::{BufWriter, Write};
61	let mut out = BufWriter::new(std::fs::File::create("test.txt")?);
62	for line in lines {
63	    writeln!(out, "{}", line)?;
64	}
65	out.flush()?;
66	# Ok(())
67	# }
